fun String.reverseWords(): String {
    return this.split(" ").reversed().joinToString(" ")
}

fun Int.secondsToMillis(): Long = this * 1000L

fun main() {
    val phrase = "Kotlin is awesome"
    println(phrase.reverseWords())  // awesome is Kotlin

    val seconds = 5
    println("${seconds.secondsToMillis()} ms")  // 5000 ms

    val str: String? = null
    println(str.isNullOrBlank())  // true
}
